        element.className = 'title-page';
        element.innerHTML = `<div class="title-main">${item.main}</div><div class="title-sub">${item.sub}</div>`;
    }
    else if (item.type === 'contributor') {
        element.className = 'contributor-item';
        element.innerHTML = `<span class="contributor-name">${item.name}</span><span class="contributor-detail">${item.detail}</span>`;
    }
    else if (item.type === 'section-header') {
        element.className = 'section-header';
        element.innerText = item.body;
    }
    else if (item.type === 'overview') {
        element.className = 'overview-block';
        element.innerHTML = `<span class="overview-label">Chapter Overview</span><div class="p-block">${item.body}</div>`;
    }
    else if (item.type === 'interaction-box') {
        element.className = 'interaction-container';
        const isReflection = item.label.toLowerCase().includes('reflection');

        let html = '';
        if (isReflection) {
            html += `<div class="outer-label">${item.label}</div>`;
        }

        html += `<div class="interaction-box">`;
        if (!isReflection) {
            html += `<span class="interaction-label">${item.label}</span>`;
        }

        if (item.questions) {
            html += '<ul>' + item.questions.map(q => `<li>${q}</li>`).join('') + '</ul>';
        } else {
            html += item.body || '';
        }
        html += `</div>`;
        element.innerHTML = html;
    }
    else if (item.type === 'summary') {
        element.className = 'summary-block';
        let list = `<span class="summary-label">Summary</span><ul>`;
        item.points.forEach(p => list += `<li>${p}</li>`);
        element.innerHTML = list + '</ul>';
    }
    else if (item.type === 'definition-box') {
        element.className = 'definition-highlight';
        element.innerHTML = `<ul><li>${item.body}</li></ul>`;
    }
    else if (item.type === 'spacer') {
        element.style.flexGrow = item.flex || '0';
        element.style.height = item.height || '0px';
    }

    // APPLY GRANULAR STYLES
    if (item.style) {
        if (item.style.align) element.style.textAlign = item.style.align;
        if (item.style.bold) element.style.fontWeight = 'bold';
        if (item.style.size) element.style.fontSize = item.style.size;
        if (item.style.marginTop) element.style.marginTop = item.style.marginTop;
        if (item.style.marginBottom) element.style.marginBottom = item.style.marginBottom;
        if (item.style.color) element.style.color = item.style.color;
        if (item.style.italic) element.style.fontStyle = 'italic';
    }

    pageDiv.appendChild(element);
});
