        const data = item.items || item.points || [];
        data.forEach(li => list += `<li>${li}</li>`);
        element.innerHTML = list + '</ol>';
    }
    else if (item.type === 'bullet-list') {
        element.className = 'list-block';
        let list = '<ul>';
        const data = item.items || item.points || [];
        data.forEach(li => list += `<li>${li}</li>`);
        element.innerHTML = list + '</ul>';
    }
    else if (item.type === 'bullet-list') {
        element.className = 'list-block';
        let list = '<ul>';
        const data = item.items || item.points || [];
        data.forEach(li => list += `<li>${li}</li>`);
        element.innerHTML = list + '</ul>';
    }
    else if (item.type === 'toc') {
        element.className = 'toc-container';
        const list = item.entries || item.items || [];
        list.forEach(entry => {
            const row = document.createElement('div');
            const text = entry.text || entry.label || (typeof entry === 'string' ? entry : '');
            const page = entry.page || '';
            const level = entry.level || 0;

            row.className = `toc-entry level-${level}`;
            row.innerHTML = `
                <span class="toc-text">${text}</span>
                <span class="toc-dots"></span>
