fun getDirectoryContents(path: String): List<FileItem> {
    val directory = File(path)
    val items = mutableListOf<FileItem>()
    try {
        if (directory.exists() && directory.isDirectory) {
            val files = directory.listFiles()
            files?.forEach { file ->
                val isDir = file.isDirectory
                items.add(FileItem(
                    name = file.name,
                    meta = if (isDir) "Folder" else "${file.length() / 1024} KB",
                    icon = if (isDir) Icons.Default.Folder else Icons.Default.Description,
                    color = if (isDir) Color(0xFF00E5FF) else Color.Gray,
                    path = file.absolutePath
                ))
            }
        }
    } catch (e: Exception) { }
